/// Step handler trait for ExampleSaga flow
#[async_trait::async_trait]
pub trait ExampleSagaStepHandler: Send + Sync {
    /// Handle validate step
    async fn handle_validate(
        &self,
        instance: &mut ExampleSagaFlowInstance,
    ) -> Result<Option<ExampleSagaFlowStep>, FlowError>;

    /// Handle write_example step
    async fn handle_write_example(
        &self,
        instance: &mut ExampleSagaFlowInstance,
    ) -> Result<Option<ExampleSagaFlowStep>, FlowError>;

    /// Handle terminal step done
    async fn handle_done(
        &self,
        instance: &mut ExampleSagaFlowInstance,
    ) -> Result<(), FlowError>;

    /// Handle terminal step rejected
    async fn handle_rejected(
        &self,
        instance: &mut ExampleSagaFlowInstance,
    ) -> Result<(), FlowError>;

}

/// Executor for ExampleSaga flow
pub struct ExampleSagaFlowExecutor<H: ExampleSagaStepHandler> {
    handler: Arc<H>,
}

impl<H: ExampleSagaStepHandler> ExampleSagaFlowExecutor<H> {
    /// Create a new flow executor
    pub fn new(handler: Arc<H>) -> Self {
        Self { handler }
    }

    /// Start a new flow instance
    pub async fn start(&self, instance_id: impl Into<String>) -> Result<ExampleSagaFlowInstance, FlowError> {
        let mut instance = ExampleSagaFlowInstance::new(instance_id);
        instance.status = ExampleSagaFlowStatus::Running;
        instance.current_step = Some(ExampleSagaFlowStep::Validate);
        Ok(instance)
    }

    /// Execute the current step
    pub async fn execute_step(&self, instance: &mut ExampleSagaFlowInstance) -> Result<(), FlowError> {
        let current_step = match instance.current_step {
            Some(step) => step,
            None => return Err(FlowError::NoCurrentStep),
        };

        let next_step = match current_step {
            ExampleSagaFlowStep::Validate => {
                self.handler.handle_validate(instance).await?
            }
            ExampleSagaFlowStep::WriteExample => {
                self.handler.handle_write_example(instance).await?
            }
            ExampleSagaFlowStep::Done => {
                self.handler.handle_done(instance).await?;
                None // Terminal step
            }
            ExampleSagaFlowStep::Rejected => {
                self.handler.handle_rejected(instance).await?;
                None // Terminal step
            }
        };

        // Mark current step as completed
        instance.completed_steps.push(current_step);

        // Move to next step
        match next_step {
            Some(next) => {
                instance.current_step = Some(next);
            }
            None => {
                instance.current_step = None;
                instance.status = ExampleSagaFlowStatus::Completed;
            }
        }

        instance.updated_at = chrono::Utc::now();
        Ok(())
    }

    /// Run the flow to completion
    pub async fn run(&self, instance: &mut ExampleSagaFlowInstance) -> Result<(), FlowError> {
        while !instance.is_complete() && instance.status != ExampleSagaFlowStatus::Waiting {
            self.execute_step(instance).await?;
        }
        Ok(())
    }

    /// Cancel the flow
    pub fn cancel(&self, instance: &mut ExampleSagaFlowInstance) {
        instance.status = ExampleSagaFlowStatus::Cancelled;
        instance.updated_at = chrono::Utc::now();
    }

    /// Mark flow as failed
    pub fn fail(&self, instance: &mut ExampleSagaFlowInstance, error: impl Into<String>) {
        instance.status = ExampleSagaFlowStatus::Failed;
        instance.error = Some(error.into());
        instance.updated_at = chrono::Utc::now();
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_flow_instance_creation() {
        let instance = ExampleSagaFlowInstance::new("test-1");
        assert_eq!(instance.id, "test-1");
        assert_eq!(instance.status, ExampleSagaFlowStatus::Pending);
        assert!(!instance.is_complete());
    }

    #[test]
    fn test_flow_context() {
        let mut instance = ExampleSagaFlowInstance::new("test-2");
        instance.set_context("key", serde_json::json!("value"));
        let value = instance.get_context("key");
        assert_eq!(value, Some(&serde_json::json!("value")));
    }

    #[test]
    fn test_flow_status_transitions() {
        let mut instance = ExampleSagaFlowInstance::new("test-3");
        assert!(!instance.is_running());

        instance.status = ExampleSagaFlowStatus::Running;
        assert!(instance.is_running());
        assert!(!instance.is_complete());

        instance.status = ExampleSagaFlowStatus::Completed;
        assert!(instance.is_complete());
        assert!(!instance.is_running());
    }
}